




































































































import Vue from "vue";
import {validateSize} from 'nano-grid/modules/columns-manager.js';
import panelBlock from "../components/panel-block.vue";
import panelBlockColumn from "../components/panel-block-column.vue";
import PanelNavigation from "../components/panel-navigation.vue";

export default Vue.extend({
  components: {
    PanelNavigation,
    panelBlock,
    panelBlockColumn
  },
  data: () => ({
    state: {
      panel: true,
    },
    selection: {
      row: "Row",
      integrate: false,
      spacing: 0,
      columns: [
        {
            mode: "Percent",
            size: "50%",
            subtraction: "0",
            color: "denim",
            expression: "sz1b4",
            block: "column",
        },
        {
            mode: "Percent",
            size: "50%",
            subtraction: "0",
            color: "persian-red",
            expression: "sz1b4",
            block: "column",
        },
      ]
    },
    spacing: [
      0,
      25,
      50,
      75,
      100,
      125,
      150,
      175,
      200,
      225,
      250,
      275,
      300,
      325,
      350,
      375,
      400,
    ],
  }),
  computed: {
    fixesValues():Array<string> {
      let result = [];
      for(let c = 5; c <= 60; c++ ){
        result.push(`${c * 5}`);
      }
      return result;
    },
    fixesSubstractionValues():Array<string> {
      let result = [];
      for(let c = 1; c <= 120; c++ ){
        result.push(`${c * 5}`);
      }
      return result;
    },
    percentsValues():Array<string> {
      let result = [];
      for(let c = 1; c*5 <= 100; c++ ){
        result.push(`${c * 5}%`);
      }
      return result;
    },
    twelveValues():Array<string> {
      let result = [];
      for(let c = 1; c <= 12; c++ ){
        result.push(`${c}/12`);
      }
      return result;
    },
    columnsValues():Array<string> {
      let result = [];
      for(let c = 1; c <= 20; c++ ){
        result.push(`1/${c}`);
      }
      return result;
    },
    computedSpacing():number {
      return this.selection.row === 'Row' ? this.selection.spacing : 0;
    },
    computedIntegrate():boolean {
      return this.selection.row === 'Group' ? this.selection.integrate : false;
    },
    rowSize():string {
      let subtraction = 0
      let fraction = 0
      let fixVal = 0;
      let columns = this.selection.columns;

      columns.forEach(column => {
          subtraction += parseInt(column.subtraction);

          let isPercent = /[%]/.test(column.size);
          let isFraction = /[/]/.test(column.size);
          if(isPercent){
              fraction += parseInt(column.size);
          } else if(isFraction) {
              let parts = column.size.split('/');
              fraction += parseInt(parts[0]) / parseInt(parts[1]) * 100;
          } else {
              fixVal += parseInt(column.size);
          }
      });
      let fixResult = fixVal-subtraction > -1 ? '+' + (fixVal-subtraction).toString() : (fixVal-subtraction).toString();
      return `${fraction}%${fixResult}`;
    }
  },
  methods: {
    finalExpression(column:number):string {
      let result = "";
      if(this.selection.columns[column].size){
        result += this.selection.columns[column].size;
        if(parseInt(this.selection.columns[column].subtraction) > 0){
          result += `-${this.selection.columns[column].subtraction}`;
        }
      }
      return validateSize(result);
    },
    addColumn():any {
        this.selection.columns.push(
            {
              mode: "Percent",
              size: "50%",
              subtraction: "0",
              color: "desert",
              expression: "sz1b4",
              block: "column",
            }
        );
    },
    togglePanel():any {
      this.state.panel = !this.state.panel;
    }
  },
});
